import { unstable_cache, revalidateTag } from 'next/cache';

/**
 * Module-level sync state.
 * In a production deployment this would live in a shared store (Redis, DB, etc.)
 * so all instances see the same state.
 */

let syncInProgress = false;
let lastSyncCompleted = null;

/**
 * Internal — fetches products from the data source (simulated DB / ERP).
 * Not cached; callers should go through getAllProducts instead.
 */
async function fetchProducts() {
  // Simulate database / ERP query latency
  await new Promise((resolve) => setTimeout(resolve, 100));

  return [
    { id: 1, name: 'Laptop', price: 999 },
    { id: 2, name: 'Phone', price: 699 },
    { id: 3, name: 'Tablet', price: 499 },
    { id: 4, name: 'Headphones', price: 199 },
    { id: 5, name: 'Watch', price: 299 },
  ];
}

/**
 * Returns the cached product catalog tagged with "products".
 *
 * - First call per cache-life fetches from the simulated source.
 * - Subsequent calls serve the cached entry until the "products" tag
 *   is revalidated (via revalidateTag('products')).
 */
export const getAllProducts = unstable_cache(fetchProducts, ['products-list'], {
  tags: ['products'],
});

/**
 * Triggers a background catalog sync from the upstream ERP/PIM source.
 *
 * Returns immediately so the admin can continue working. The product list
 * remains stale until the background job finishes and revalidates the
 * "products" cache tag.
 *
 * This is the **eventual consistency** pattern: the admin gets a responsive
 * UI while the system converges to fresh data across every view that uses
 * the same "products" tag.
 */
export function triggerCatalogSync() {
  if (syncInProgress) {
    return { success: false, message: 'Sync already in progress.' };
  }

  syncInProgress = true;

  // Fire-and-forget — the admin does NOT wait for this to finish.
  runBackgroundSync().catch(() => {
    syncInProgress = false;
  });

  return { success: true, message: 'Catalog sync started.' };
}

/**
 * Background job that simulates an ERP/PIM data pull (slow — touches
 * thousands of SKUs in production). Once it completes it invalidates
 * the "products" cache tag so downstream views pick up fresh data.
 */
async function runBackgroundSync() {
  try {
    // Simulate the latency of a real ERP/PIM data pull
    await new Promise((resolve) => setTimeout(resolve, 5000));

    // Invalidate every cache entry tagged "products".
    // All views (catalog page, search, detail pages) that tag their
    // fetches with "products" will serve fresh data on the next request.
    revalidateTag('products');

    lastSyncCompleted = Date.now();
  } finally {
    syncInProgress = false;
  }
}

